+/** Record a target-specific relation event and update affected tracking queries. */
+export function setPairTrackingEvent(
+    world: World,
+    entity: Entity,
+    trait: Trait,
+    target: Entity,
+    eventType: 'add' | 'remove' | 'change'
+) {
+    const data = getTraitInstance(world[$internal].traitInstances, trait);
+    if (!data) return;
+
+    const eid = getEntityId(entity);
+    const key = `${trait.id}:${target}`;
+    for (const query of data.trackingQueries) {
+        let hasPair = false;
+        for (const group of query.trackingGroups) {
